/**
 * 模块职责：构造按事件槽位的小总结和大总结固定文本协议。
 * 维护边界：模型不返回 eventId 或 JSON；插件用本次请求 slot 映射内部事件线与版本链。
 */
import type { InternalFact, SummaryArtifact } from '../types';

export function smallSummarySystemPrompt(): string {
  return `你是镜渊阶段沉降结算器。你按本次请求提供的 slot 分别总结事件线，不续写，不推测，不把未发生结果写死。

必须返回固定文本协议，禁止JSON、Markdown代码块、解释和思考标签。每个输入 slot 必须且只能返回一个：
<MA_SUMMARY>
slot=S1
title=事件线标题
summary=累计小总结；允许自然语言续行
keyword=关键词（可重复多行）
unresolved=尚未解决事项（可重复多行）
</MA_SUMMARY>

规则：
1. 不同 slot 绝不能混合人物、地点、因果或结果。
2. 小总结不是聊天流水账；保留起因、关键经过、已产生变化、当前结果、未决事项和后续仍有效的影响。
3. 删除重复动作、气氛描写、无因果作用的旁观者、观众、路人，无后续意义的临时反应和被新事实覆盖的旧表述。
4. 事件未结束时，只总结已确认部分，并明确未决事项。
5. slot 只是本次请求路由标签，必须原样返回；不要输出任何内部 ID。`;
}

export interface SmallSummaryEventBatch {
  slot?: string;
  eventId: string;
  facts: InternalFact[];
  previous?: SummaryArtifact;
}

function lines(values: unknown[]): string {
  return values.map((item) => `- ${String(item ?? '').trim()}`).filter((item) => item !== '-').join('\n') || '（无）';
}

function smallEventSection(group: SmallSummaryEventBatch, index: number): string {
  const slot = group.slot || `S${index + 1}`;
  const facts = group.facts.map((fact, factIndex) => `事实${factIndex + 1}
标题：${fact.title}
已发生：${lines(fact.occurredFacts)}
未决：${lines(fact.unresolvedItems)}
状态：${fact.status}
时间：${[fact.timeRange.start, fact.timeRange.end, fact.timeRange.label].filter(Boolean).join(' / ') || '未标注'}
直接影响对象：${lines(fact.relatedEntities)}
置信度：${fact.confidence}`).join('\n\n');
  return `【事件槽位 ${slot}】
内部事件名称（只用于理解，不要输出）：${group.eventId}

上一版小总结：
${group.previous ? `标题：${group.previous.title}\n摘要：${group.previous.summary}\n未决：${lines(group.previous.unresolvedItems ?? [])}\n关键词：${lines(group.previous.keywords)}` : '（无）'}

本次新增事实：
${facts || '（无）'}`;
}

export function smallSummaryBatchPrompt(groups: SmallSummaryEventBatch[]): string {
  return `为下列事件槽位分别生成自己的累计小总结。只使用各槽位的上一版小总结和新增内部事实，不读取或补全聊天正文。

${groups.map(smallEventSection).join('\n\n====================\n\n')}

按输入顺序返回 <MA_SUMMARY>。每个 slot 必须且只能出现一次。`;
}

export function smallSummaryPrompt(eventId: string, facts: InternalFact[], previous?: SummaryArtifact): string {
  return smallSummaryBatchPrompt([{ slot: 'S1', eventId, facts, previous }]);
}

export interface LargeSummaryEventBatch {
  slot?: string;
  eventId: string;
  latestSmall: SummaryArtifact;
  sourceSummaryIds: string[];
  previousLarge?: SummaryArtifact;
}

export function largeSummarySystemPrompt(): string {
  return `你是镜渊长期沉降结算器。你按本次请求提供的 slot 分别生成长期总结，不读取聊天正文，不补全未显影内容。

必须返回固定文本协议，禁止JSON、Markdown代码块、解释和思考标签。每个输入 slot 必须且只能返回一个：
<MA_SUMMARY>
slot=L1
title=事件线标题
summary=累计长期总结；允许自然语言续行
keyword=关键词（可重复多行）
unresolved=仍未解决事项（可重复多行）
</MA_SUMMARY>

规则：
1. 不同 slot 绝不能混合事实、因果、人物或地点。
2. 只固化已经发生的结果、核心因果、长期影响和仍未解决事项。
3. 删除动作细节、重复过程和已被结果覆盖的描述。
4. slot 只是本次请求路由标签，必须原样返回；不要输出任何内部 ID。`;
}

function largeEventSection(group: LargeSummaryEventBatch, index: number): string {
  const slot = group.slot || `L${index + 1}`;
  return `【事件槽位 ${slot}】
内部事件名称（只用于理解，不要输出）：${group.eventId}

上一版长期总结：
${group.previousLarge ? `标题：${group.previousLarge.title}\n摘要：${group.previousLarge.summary}\n未决：${lines(group.previousLarge.unresolvedItems ?? [])}\n关键词：${lines(group.previousLarge.keywords)}` : '（无）'}

最新累计小总结：
标题：${group.latestSmall.title}
摘要：${group.latestSmall.summary}
未决：${lines(group.latestSmall.unresolvedItems ?? [])}
关键词：${lines(group.latestSmall.keywords)}`;
}

export function largeSummaryPrompt(groups: LargeSummaryEventBatch[]): string {
  return `将下列事件槽位分别压缩为自己的累计长期总结。没有介入或改变长期因果的旁观者、观众、路人不得进入长期总结。

${groups.map(largeEventSection).join('\n\n====================\n\n')}

按输入顺序返回 <MA_SUMMARY>。每个 slot 必须且只能出现一次。`;
}
