/**
 * 模块职责：解析和执行规则审核，并应用标记、隐藏或进入修正的结果。
 * 维护边界：技术故障与内容违规必须分开；缺少合法 result 的对象不能默认判为违规。
 */
import { getSettings, messageFingerprint, toast } from '../core/context';
import { assertArtifactCommitCurrent } from '../core/commit-guard';
import { hashText, safeText, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { describeTaskConnection, generateTask } from '../llm/generator';
import { auditSystemPrompt, auditUserPrompt } from '../prompts/audit';
import { putArtifact } from '../storage/repository';
import type { AuditResult, MessageArtifact } from '../types';
import { parseAuditTextOutput } from '../domain/audit-text';

/** 审核模型只返回固定文本；插件负责转换为内部对象。 */
export function parseAuditResult(raw: unknown): AuditResult {
  return parseAuditTextOutput(raw);
}

export function findMessageElement(index: number): HTMLElement | null {
  return document.querySelector<HTMLElement>(`.mes[mesid="${index}"], .mes[data-message-id="${index}"], #chat .mes:nth-of-type(${index + 1})`);
}

export function applyAuditVisibility(index: number, hidden: boolean, marked = false): void {
  const element = findMessageElement(index);
  element?.classList.toggle('ma11-audit-hidden-message', hidden);
  element?.classList.toggle('ma11-audit-marked-message', !hidden && marked);
}

function isCancelledAuditRequest(error: unknown): boolean {
  return error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name);
}

export async function auditText(playerRules: string, playerText: string, assistantText: string): Promise<AuditResult> {
  const raw = await generateTask({
    task: 'audit',
    systemPrompt: auditSystemPrompt(),
    prompt: auditUserPrompt(playerRules, playerText, assistantText),
    requestPurpose: 'fixed-text',
  });
  try {
    return parseAuditResult(raw);
  } catch (error) {
    const preview = safeText(raw, 1200).replace(/\s+/g, ' ').trim();
    throw new Error(
      `规则审核未返回有效固定文本（${describeTaskConnection('audit')}）。${toErrorMessage(error)}${preview ? `；返回片段：${preview}` : ''}`,
      { cause: error },
    );
  }
}

export async function applyAuditFailureAction(
  artifact: MessageArtifact,
  action: 'mark' | 'hide' | 'delete',
): Promise<void> {
  if (action === 'mark') {
    artifact.hiddenByAudit = false;
    applyAuditVisibility(artifact.messageIndex, false, true);
    return;
  }
  if (action === 'hide') {
    artifact.hiddenByAudit = true;
    applyAuditVisibility(artifact.messageIndex, true);
    return;
  }
  artifact.hiddenByAudit = true;
  applyAuditVisibility(artifact.messageIndex, true);
  toast('warning', '审核未通过；插件不会自动删除酒馆消息，已隐藏并保留人工处理入口');
}

/**
 * 审核只决定当前正文是否通过以及后续是否需要修正；技术异常由调用方按失败状态处理。
 */
export async function runAudit(artifact: MessageArtifact, force = false): Promise<AuditResult> {
  const settings = getSettings();
  artifact.stages.revision ||= { status: 'idle', attempts: 0 };
  if (!settings.auditEnabled) {
    markStage(artifact, 'audit', 'skipped');
    markStage(artifact, 'revision', 'skipped');
    artifact.hiddenByAudit = false;
    applyAuditVisibility(artifact.messageIndex, false, false);
    artifact.audit = {
      passed: true,
      decision: 'pass',
      reason: '未启用规则审核',
      violations: [],
      preserve: [],
      rewriteInstruction: '',
      violationFingerprint: '',
    };
    await putArtifact(artifact);
    return artifact.audit;
  }
  if (!settings.auditPrompt.trim()) throw new Error('已启用规则审核，但审核提示词为空');
  const ruleFingerprint = hashText(`${settings.auditPrompt}\n${settings.auditFailAction}\n${settings.maxRevisionAttempts}`);
  if (
    !force
    && artifact.stages.audit.status === 'success'
    && artifact.audit?.passed
    && artifact.approvedFingerprint === artifact.sourceFingerprint
    && (!(artifact as any).auditRuleFingerprint || (artifact as any).auditRuleFingerprint === ruleFingerprint)
  ) {
    (artifact as any).auditRuleFingerprint = ruleFingerprint;
    return artifact.audit;
  }

  markStage(artifact, 'audit', 'running');
  await putArtifact(artifact);
  try {
    const result = await auditText(settings.auditPrompt, artifact.playerText, artifact.assistantText);
    assertArtifactCommitCurrent(artifact);
    artifact.audit = result;
    (artifact as any).auditRuleFingerprint = ruleFingerprint;
    if (result.passed) {
      artifact.approvedFingerprint = artifact.sourceFingerprint;
      artifact.hiddenByAudit = false;
      applyAuditVisibility(artifact.messageIndex, false, false);
      markStage(artifact, 'audit', 'success');
      markStage(artifact, 'revision', 'skipped');
    } else {
      markStage(artifact, 'audit', 'blocked', result.reason);
    }
    // 审核阶段只更新内存 artifact；业务编排器负责在明确检查点统一保存。
    // 避免审核函数与主链紧邻地重复保存同一条聊天。
    await putArtifact(artifact);
    return result;
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) {
      markStage(artifact, 'audit', 'cancelled', toErrorMessage(error));
      await putArtifact(artifact);
      throw error;
    }
    markStage(artifact, 'audit', 'failed', toErrorMessage(error));
    await putArtifact(artifact);
    throw error;
  }
}
