/**
 * 模块职责：解析模型返回的固定标签文本协议。
 * 维护边界：只处理文本边界、重复字段和续行；业务字段、对象身份与持久化由各领域模块负责。
 */
import { safeText } from '../core/utils';

export interface FixedTextMarker {
  kind: string;
  start: string;
  end: string;
  rawBody?: boolean;
}

export interface FixedTextBlock {
  kind: string;
  fields: Map<string, string[]>;
  raw: string;
  line: number;
}

function normalizedMarker(value: string): string {
  return value.trim().toUpperCase();
}

function appendField(block: FixedTextBlock, key: string, value: string): void {
  const current = block.fields.get(key) ?? [];
  block.fields.set(key, [...current, value]);
}

function appendContinuation(block: FixedTextBlock, key: string, value: string): void {
  const current = block.fields.get(key) ?? [];
  if (!current.length) return;
  const next = [...current];
  next[next.length - 1] = `${next[next.length - 1]}\n${value}`.trim();
  block.fields.set(key, next);
}

/**
 * 支持：英文/中文等号、英文/中文冒号、重复字段、多行续写、原文块。
 * 未闭合块会在文本结束时收口，避免单个缺失结束标签吞掉整次请求。
 */
export function parseFixedTextBlocks(raw: unknown, markers: FixedTextMarker[]): FixedTextBlock[] {
  const source = safeText(raw, 240000).replace(/^\uFEFF/, '');
  const byStart = new Map(markers.map((item) => [normalizedMarker(item.start), item]));
  const byEnd = new Map(markers.map((item) => [normalizedMarker(item.end), item]));
  const blocks: FixedTextBlock[] = [];
  let current: FixedTextBlock | null = null;
  let definition: FixedTextMarker | null = null;
  let lastKey = '';
  let rawLines: string[] = [];

  const flush = () => {
    if (!current) return;
    if (definition?.rawBody) current.raw = rawLines.join('\n').trim();
    blocks.push(current);
    current = null;
    definition = null;
    lastKey = '';
    rawLines = [];
  };

  source.split(/\r?\n/).forEach((sourceLine, index) => {
    const trimmed = sourceLine.trim();
    const markerKey = normalizedMarker(trimmed);
    const start = byStart.get(markerKey);
    if (start) {
      flush();
      definition = start;
      current = { kind: start.kind, fields: new Map(), raw: '', line: index + 1 };
      return;
    }
    const end = byEnd.get(markerKey);
    if (end) {
      if (current?.kind === end.kind) flush();
      return;
    }
    if (!current || !definition) return;
    if (definition.rawBody) {
      rawLines.push(sourceLine);
      return;
    }
    if (!trimmed || /^```/.test(trimmed)) return;
    const match = sourceLine.match(/^\s*([^=＝:：]+?)\s*[=＝:：]\s*(.*)$/);
    if (match) {
      lastKey = match[1].trim();
      if (lastKey) appendField(current, lastKey, match[2].trim());
      return;
    }
    if (lastKey) appendContinuation(current, lastKey, sourceLine.trim());
  });
  flush();
  return blocks;
}

export function fixedTextValues(block: FixedTextBlock, ...keys: string[]): string[] {
  const output: string[] = [];
  const seen = new Set<string>();
  for (const key of keys) {
    for (const raw of block.fields.get(key) ?? []) {
      const value = safeText(raw, 12000).trim();
      if (!value || seen.has(value)) continue;
      seen.add(value);
      output.push(value);
    }
  }
  return output;
}

export function fixedTextValue(block: FixedTextBlock, ...keys: string[]): string {
  return fixedTextValues(block, ...keys).at(-1) ?? '';
}
