/**
 * 模块职责：解析小总结和大总结的固定文本协议，并按本次请求槽位回收结果。
 * 维护边界：模型只返回 slot 与自然语言；eventId、总结 ID、版本链和持久化全部由插件维护。
 */
import { safeText } from '../core/utils';
import { fixedTextValue, fixedTextValues, parseFixedTextBlocks } from './fixed-text';

const MARKERS = [{ kind: 'summary', start: '<MA_SUMMARY>', end: '</MA_SUMMARY>' }];

export interface ParsedSummaryText {
  slot: string;
  title: string;
  summary: string;
  keywords: string[];
  unresolved: string[];
}

function normalizeKey(value: string): string {
  const raw = value.normalize('NFKC').trim();
  const aliases: Record<string, string> = {
    '槽位': 'slot', '编号': 'slot', '标题': 'title', '摘要': 'summary', '关键词': 'keyword', '未决': 'unresolved', '未解决': 'unresolved',
  };
  return aliases[raw] || raw.toLowerCase().replace(/[\s_-]+/g, '');
}

function normalizedBlock(block: ReturnType<typeof parseFixedTextBlocks>[number]) {
  const fields = new Map<string, string[]>();
  for (const [key, values] of block.fields.entries()) {
    const target = normalizeKey(key);
    fields.set(target, [...(fields.get(target) ?? []), ...values]);
  }
  return { ...block, fields };
}

export function parseSummaryTextOutput(raw: unknown, expectedSlots: string[]): Map<string, ParsedSummaryText> {
  const expected = new Set(expectedSlots);
  const blocks = parseFixedTextBlocks(raw, MARKERS).filter((block) => block.kind === 'summary');
  if (!blocks.length) throw new Error('总结模型未返回 <MA_SUMMARY>');
  const output = new Map<string, ParsedSummaryText>();
  for (const source of blocks) {
    const block = normalizedBlock(source);
    const slot = fixedTextValue(block, 'slot').trim().toUpperCase();
    if (!slot) throw new Error(`第 ${block.line} 行开始的 <MA_SUMMARY> 缺少 slot`);
    if (!expected.has(slot)) throw new Error(`总结返回未请求槽位：${slot}`);
    if (output.has(slot)) throw new Error(`总结重复返回槽位：${slot}`);
    const summary = safeText(fixedTextValue(block, 'summary'), 20000).trim();
    if (!summary) throw new Error(`总结槽位 ${slot} 的 summary 为空`);
    output.set(slot, {
      slot,
      title: safeText(fixedTextValue(block, 'title'), 1000).trim(),
      summary,
      keywords: fixedTextValues(block, 'keyword').map((item) => safeText(item, 200).trim()).filter(Boolean).slice(0, 40),
      unresolved: fixedTextValues(block, 'unresolved').map((item) => safeText(item, 2000).trim()).filter(Boolean).slice(0, 40),
    });
  }
  for (const slot of expectedSlots) if (!output.has(slot)) throw new Error(`总结缺少槽位结果：${slot}`);
  return output;
}
