/**
 * 模块职责：动态表格注册、旧表迁移、对象视图字段归一化与注册表操作。
 * 维护边界：表格只是对象/事实视图；删除或停用视图不能删除内部事实、事件线或总结。
 */
import { type TableDefinition, type TableFieldDefinition, type TableRole } from '../constants';
import { deepClone, hashText, safeText } from '../core/utils';

export const CORE_FIELD_KEYS = [
  'id', 'title', 'content', 'keywords', 'status', 'factIds', 'eventId', 'recall',
  'baseContent', 'currentFacts', 'currentStates', 'recentHistory', 'solidifiedHistory', 'relatedObjects', 'relatedEvents',
  'relationshipStates', 'abilityStates', 'objectType', 'migrationStatus',
] as const;

/** 玩家可改的是语义表头，不是底层字段身份。 */
export const EDITABLE_HEADER_FIELD_KEYS = ['title', 'content', 'status', 'keywords'] as const;
const EDITABLE_HEADER_FIELD_KEY_SET = new Set<string>(EDITABLE_HEADER_FIELD_KEYS);
const RESERVED_CUSTOM_FIELD_KEYS = new Set<string>([
  ...CORE_FIELD_KEYS,
  'name', 'summary', 'source', 'locked', 'lockMode', 'lifecycle', 'updatedAt',
  'fact_ids', 'event_id', 'fields', '__proto__', 'prototype', 'constructor',
]);

