/**
 * 模块职责：集中定义版本、任务类型、动态表格设置与默认值。
 * 维护边界：表格数量和名称不得在业务模块中写死，默认表仅用于首次初始化和恢复默认。
 */
export const MODULE_NAME = 'mirrorAbyssV11';
export const LEGACY_MODULE_NAME = 'mirrorAbyss';
export const DISPLAY_NAME = '镜渊';
export const VERSION = '1.2.0-rc.53';
export const PIPELINE_VERSION = 'ma-pipeline-53';

/** 表格键为运行时注册值，不再由常量数组限制数量。 */
export type TableKey = string;

/**
 * focus/state/skills/relationships 只为读取 rc.22 及更早注册表保留；默认运行时不会重新创建这些旧视图。
 * 删除这些兼容角色前，必须先提供旧设置与旧快照的显式迁移，否则历史聊天会丢表。
 */
export type TableRole = 'spacetime' | 'characters' | 'items' | 'events' | 'regions' | 'globalChanges' | 'foundations' | 'custom' | 'focus' | 'state' | 'skills' | 'relationships';
export type TableFieldType = 'string' | 'string[]' | 'lifecycle';
export interface TableFieldDefinition { key: string; label: string; description: string; type: TableFieldType; required: boolean; }
export interface TableDefinition {
  key: string;
  name: string;
  purpose: string;
  role: TableRole;
  enabled: boolean;
  order: number;
  isDefault: boolean;
  fields: TableFieldDefinition[];
}

export type TaskKind = 'audit' | 'revision' | 'state' | 'smallSummary' | 'largeSummary';
export type ConnectionMode = 'current' | 'profile';
export interface TaskConnectionSettings { mode: ConnectionMode; profileId: string; profile: string; }
export type AuditFailAction = 'mark' | 'hide' | 'revise';
export type RevisionFallbackAction = 'mark' | 'hide';

export interface MirrorAbyssSettings {
  enabled: boolean;
  autoState: boolean;
  showMessagePanel: boolean;
  showTopButton: boolean;
  auditEnabled: boolean;
  auditPrompt: string;
  auditFailAction: AuditFailAction;
  revisionPrompt: string;
  maxRevisionAttempts: number;
  stopOnRepeatedViolation: boolean;
  revisionFallbackAction: RevisionFallbackAction;
  autoSmallSummary: boolean;
  smallSummaryTurns: number;
  autoLargeSummary: boolean;
  largeSummaryCount: number;
  lorebookSync: boolean;
  autoCreateLorebook: boolean;
  lorebookName: string;
  vectorizeRows: boolean;
  latestContinuityConstant: boolean;
  lorebookLayout: 'semantic' | 'detailed';
  lorebookRecall: { similarityThreshold: number; maxVectorResults: number; totalCapacity: number };
  requestTimeoutMs: number;
  tableRegistry: TableDefinition[];
  connections: Record<TaskKind, TaskConnectionSettings>;
  ui: {
    activeTab: 'overview' | 'tables' | 'tableManager' | 'graph' | 'summaries' | 'audit' | 'sync' | 'settings' | 'diagnostics';
    activeTable: string;
    graphScope: 'relations' | 'world';
    graphZoom: number;
  };
  migration: { legacyChecked: boolean; dynamicTablesV23: boolean; objectViewsV26: boolean };
}

