/**
 * 模块职责：归一化按 event_id 生成的小总结与仅消费未固化小总结的大总结。
 * 维护边界：总结是派生记忆，不能成为内部事实层的反向真相来源。
 */
import type { CharacterActivityUpdate, SedimentationPlan, SummaryArtifact } from '../types';
import { makeId, nowIso, safeText } from '../core/utils';

function stringList(value: unknown, limit = 60, itemLimit = 600): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, itemLimit).trim()).filter(Boolean))].slice(0, limit);
}
function normalizeActivityUpdates(value: unknown): CharacterActivityUpdate[] {
  if (!Array.isArray(value)) return [];
  const allowed = new Set(['休眠', '长期休眠', '已归档']);
  return value.map((item) => item && typeof item === 'object' ? item as Record<string, unknown> : {}).map((item) => ({
    rowId: safeText(item.rowId, 160).trim(), activity: safeText(item.activity, 40).trim() as CharacterActivityUpdate['activity'], reason: safeText(item.reason, 500).trim(),
  })).filter((item) => item.rowId && allowed.has(item.activity)).slice(0, 30);
}
function normalizeSedimentation(value: unknown): SedimentationPlan | undefined {
  if (!value || typeof value !== 'object') return undefined;
  const source = value as Record<string, unknown>;
  return { removeRowIds: stringList(source.removeRowIds, 50, 160), characterActivityUpdates: normalizeActivityUpdates(source.characterActivityUpdates), notes: stringList(source.notes, 30, 500) };
}

export function normalizeSummary(
  value: Record<string, any>,
  kind: 'small' | 'large',
  sourceKeys: string[],
  previousLargeSummaryId?: string,
  metadata: { eventId?: string; eventIds?: string[]; sourceFactIds?: string[]; sourceSummaryIds?: string[] } = {},
): SummaryArtifact {
  return {
    id: makeId(kind),
    kind,
    title: safeText(value.title || (kind === 'small' ? '事件线小总结' : '长期因果总结'), 240).trim(),
    summary: safeText(value.summary || '', 30000).trim(),
    keywords: stringList(value.keywords, 32, 100),
    sourceKeys: [...new Set(sourceKeys)],
    sourceFactIds: metadata.sourceFactIds ? [...new Set(metadata.sourceFactIds)] : (kind === 'small' ? [...new Set(sourceKeys)] : undefined),
    sourceSummaryIds: kind === 'large' ? [...new Set(metadata.sourceSummaryIds ?? sourceKeys)] : undefined,
    eventId: safeText(metadata.eventId || value.event_id || value.eventId, 160).trim() || undefined,
    eventIds: kind === 'large' ? [...new Set(metadata.eventIds ?? (metadata.eventId ? [metadata.eventId] : []))] : undefined,
    unresolvedItems: stringList(value.unresolved ?? value.unresolvedItems, 40, 1000),
    createdAt: nowIso(),
    sedimentation: kind === 'small' ? normalizeSedimentation(value.sedimentation) : undefined,
    previousLargeSummaryId: kind === 'large' ? previousLargeSummaryId : undefined,
  };
}
