/**
 * 模块职责：扫描聊天历史中首个 artifact 与当前正文不一致的位置。
 * 维护边界：只负责定位失效起点，不直接执行重算或清理。
 */
import type { MessageArtifact, SillyTavernMessage } from '../types';

export function firstInconsistentArtifactIndex(
  chat: SillyTavernMessage[],
  moduleName: string,
  identityAt: (index: number) => string,
  fingerprintAt: (index: number) => string,
): number {
  return chat.findIndex((message, index) => {
    const artifact = message?.extra?.[moduleName] as MessageArtifact | undefined;
    return Boolean(
      artifact &&
      (artifact.messageIndex !== index ||
        artifact.messageKey !== identityAt(index) ||
        artifact.sourceFingerprint !== fingerprintAt(index)),
    );
  });
}
