/**
 * 模块职责：跟踪活动模型请求及全局请求接收开关。
 * 维护边界：禁用、重启、历史变化和聊天切换可取消全部请求；
 * 业务抢占必须按请求类别和任务定向取消，不能误伤独立诊断。
 */
import type { TaskKind } from '../constants';

export interface ActiveRequestMetadata {
  task: TaskKind;
  requestClass: 'business' | 'diagnostic';
}

const activeControllers = new Map<AbortController, ActiveRequestMetadata>();
let acceptingRequests = true;

export function setRequestAcceptance(accepting: boolean): void {
  acceptingRequests = accepting;
}

export function beginModelRequest(metadata: ActiveRequestMetadata): AbortController {
  if (!acceptingRequests) throw new Error('镜渊已禁用，不再接受新请求');
  const controller = new AbortController();
  activeControllers.set(controller, metadata);
  return controller;
}

export function finishModelRequest(controller: AbortController): void {
  activeControllers.delete(controller);
}

export function abortActiveRequests(
  predicate: (metadata: ActiveRequestMetadata) => boolean = () => true,
): number {
  let aborted = 0;
  for (const [controller, metadata] of activeControllers) {
    if (!predicate(metadata)) continue;
    aborted += 1;
    controller.abort();
    activeControllers.delete(controller);
  }
  return aborted;
}


/** 历史内容变化会使所有业务结果失效，但只读诊断不依赖正文快照。 */
export function abortActiveBusinessRequests(): number {
  return abortActiveRequests((metadata) => metadata.requestClass === 'business');
}

/** 新正文只允许抢占自动总结业务请求；诊断和其他业务链不受影响。 */
export function abortActiveAutomaticSummaryRequests(): number {
  return abortActiveRequests((metadata) => (
    metadata.requestClass === 'business'
    && ['smallSummary', 'largeSummary'].includes(metadata.task)
  ));
}
