/**
 * 模块职责：调用状态模型并把内部事实包与动态可见表格合并为下一快照。
 * 维护边界：模型只更新启用表格；停用表格保留隐藏旧视图；人工/锁定行必须恢复。
 */
import { assertArtifactCommitCurrent, CommitRejectedError } from '../core/commit-guard';
import { getChat, getSettings } from '../core/context';
import { hashText, safeText, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { normalizeFactPackage } from '../domain/facts';
import { canonicalObjectTitle } from '../domain/object-identity';
import { enabledTables, migrateSnapshotTables, normalizeTableRegistry, registryFingerprint } from '../domain/table-registry';
import { emptySnapshot, enforceObjectViewAllocation, filterPassiveObservers, normalizeSnapshot, preserveObjectBaseLayers, preservePersistentCharacters, preserveStableObjectIds, removeFocusCharacterDuplicates } from '../domain/snapshot';
import { dedupeStrongStateRows, parseStateTextOutput } from '../domain/state-text';
import { generateTask } from '../llm/generator';
import { stateSystemPrompt, stateUserPrompt } from '../prompts/state';
import { getChatState, putArtifact } from '../storage/repository';
import type { MessageArtifact, StateRow, StateSnapshot } from '../types';

class RegistryChangedError extends CommitRejectedError {}

const FACT_OPERATIONS = new Set(['create', 'update', 'append', 'close', 'supersede']);
const FACT_CONFIDENCE = new Set(['confirmed', 'recorded', 'reported', 'uncertain']);

/** 固定文本解析后再检查镜渊业务身份约束。 */
function assertStateBusinessShape(parsed: Record<string, any>, active: ReturnType<typeof enabledTables>): void {
  const factIds = new Set<string>();
  parsed.facts.forEach((fact: unknown, index: number) => {
    if (!fact || typeof fact !== 'object' || Array.isArray(fact)) throw new Error(`facts[${index}] 必须是对象`);
    const source = fact as Record<string, unknown>;
    const factId = String(source.fact_id ?? source.factId ?? source.id ?? '').trim();
    const eventId = String(source.event_id ?? source.eventId ?? source.entity_id ?? source.entityId ?? '').trim();
    const title = String(source.title ?? '').trim();
    if (!factId) throw new Error(`facts[${index}].fact_id 不能为空`);
    if (!eventId) throw new Error(`facts[${index}].event_id 不能为空`);
    if (!title) throw new Error(`facts[${index}].title 不能为空`);
    if (factIds.has(factId)) throw new Error(`同一次状态返回包含重复 fact_id：${factId}`);
    factIds.add(factId);
    if (source.operation !== undefined && !FACT_OPERATIONS.has(String(source.operation))) throw new Error(`facts[${index}].operation 不合法`);
    if (source.confidence !== undefined && !FACT_CONFIDENCE.has(String(source.confidence))) throw new Error(`facts[${index}].confidence 不合法`);
  });

  for (const table of active) {
    const rows = parsed.snapshot[table.key];
    if (rows === undefined) continue;
    if (!Array.isArray(rows)) throw new Error(`状态表 ${table.key} 必须是数组`);
    const ids = new Set<string>();
    const titles = new Set<string>();
    rows.forEach((row: unknown, index: number) => {
      if (!row || typeof row !== 'object' || Array.isArray(row)) throw new Error(`状态表 ${table.key}[${index}] 必须是对象`);
      const source = row as Record<string, unknown>;
      const id = String(source.id ?? '').trim();
      const title = String(source.title ?? '').trim();
      if (!id) throw new Error(`状态表 ${table.key}[${index}].id 不能为空`);
      if (!title) throw new Error(`状态表 ${table.key}[${index}].title 不能为空`);
      if (ids.has(id)) throw new Error(`状态表 ${table.key} 同一次返回包含重复 id：${id}`);
      const titleToken = rowIdentityTitle(title);
      if (titleToken && titles.has(titleToken)) throw new Error(`状态表 ${table.key} 同一次返回包含重复对象：${title}`);
      ids.add(id);
      if (titleToken) titles.add(titleToken);
    });
  }
}

export function previousSnapshot(beforeIndex: number): StateSnapshot {
  const registry = getSettings().tableRegistry;
  const chat = getChat();
  for (let i = beforeIndex - 1; i >= 0; i -= 1) {
    if (chat[i]?.is_user) continue;
    const snapshot = chat[i]?.extra?.mirrorAbyssV11?.snapshot as StateSnapshot | undefined;
    if (snapshot) return normalizeSnapshot(snapshot, snapshot, registry);
    const legacy = chat[i]?.extra?.mirrorAbyss?.tableSnapshot as StateSnapshot | undefined;
    if (legacy) return normalizeSnapshot(legacy, legacy, registry);
  }
  return emptySnapshot(registry);
}

function cloneProtectedRow(row: StateRow): StateRow {
  return structuredClone(row);
}

function rowIdentityTitle(value: string): string {
  return canonicalObjectTitle(value);
}

/**
 * 完全锁定行整行恢复；普通人工行只保护身份、基础内容、已固化历史与玩家自定义基础字段，
 * 当前状态、关系、能力、关联事件仍允许依据明确事实更新。
 */
export function preserveProtectedRows(previous: StateSnapshot, next: StateSnapshot, customRegistry?: ReturnType<typeof normalizeTableRegistry>): StateSnapshot {
  const registry = normalizeTableRegistry(customRegistry);
  previous = dedupeStrongStateRows(previous, registry);
  next = dedupeStrongStateRows(next, registry);
  const mutableFields = new Set(['currentFacts', 'currentStates', 'recentHistory', 'relationshipStates', 'abilityStates', 'relatedObjects', 'relatedEvents', 'migrationStatus']);
  for (const table of registry) {
    const key = table.key;
    next[key] ||= [];
    const nextIndexById = new Map(next[key].map((row, index) => [row.id, index]));
    const nextIndexesByTitle = new Map<string, number[]>();
    next[key].forEach((row, index) => {
      const title = rowIdentityTitle(row.title);
      if (title) nextIndexesByTitle.set(title, [...(nextIndexesByTitle.get(title) ?? []), index]);
    });
    for (const row of previous[key] ?? []) {
      if (row.source !== 'manual' && !row.locked && row.lockMode !== 'all' && row.lockMode !== 'base') continue;
      const protectedRow = cloneProtectedRow(row);
      const title = rowIdentityTitle(row.title);
      const titleIndexes = title ? nextIndexesByTitle.get(title) ?? [] : [];
      const existingIndex = nextIndexById.get(row.id) ?? titleIndexes[0];
      if (existingIndex === undefined) {
        nextIndexById.set(row.id, next[key].length);
        next[key].push(protectedRow);
        continue;
      }
      if (row.locked || row.lockMode === 'all') {
        next[key][existingIndex] = protectedRow;
        continue;
      }
      const generated = next[key][existingIndex];
      const oldFields = row.fields ?? {};
      const generatedFields = generated.fields ?? {};
      const mergedFields: Record<string, unknown> = { ...structuredClone(oldFields) };
      for (const field of mutableFields) if (field in generatedFields) mergedFields[field] = structuredClone(generatedFields[field]);
      next[key][existingIndex] = {
        ...generated,
        id: row.id,
        title: row.title,
        source: 'manual',
        locked: false,
        lockMode: 'base',
        fields: mergedFields,
        factIds: [...new Set([...(row.factIds ?? []), ...(generated.factIds ?? [])])],
      };
    }
  }
  return dedupeStrongStateRows(next, registry);
}

function normalizedTitle(value: unknown): string {
  return canonicalObjectTitle(value);
}

/**
 * V35 行级补丁合并：非空数组只 upsert 返回行，未返回行和空数组都保留旧表。
 * 自动状态提取不再用 [] 承担高风险清表语义；未来清表必须走独立显式操作。
 * 旧模型若仍返回完整表，也会按同一规则逐行覆盖，不产生重复。
 */
export function mergeStateRowPatches(
  previous: StateSnapshot,
  parsedSnapshot: Record<string, unknown>,
  registry: ReturnType<typeof normalizeTableRegistry>,
): StateSnapshot {
  const merged: Record<string, unknown> = {};
  for (const table of registry) merged[table.key] = structuredClone(previous[table.key] ?? []);
  for (const table of enabledTables(registry)) {
    if (!Object.prototype.hasOwnProperty.call(parsedSnapshot, table.key)) continue;
    const patches = parsedSnapshot[table.key];
    if (!Array.isArray(patches)) continue;
    if (patches.length === 0) continue;
    const rows = structuredClone(previous[table.key] ?? []) as StateRow[];
    const idIndex = new Map(rows.map((row, index) => [row.id, index]));
    const titleIndexes = new Map<string, number[]>();
    rows.forEach((row, index) => {
      const title = normalizedTitle(row.title);
      if (title) titleIndexes.set(title, [...(titleIndexes.get(title) ?? []), index]);
    });
    const patchTitleCounts = new Map<string, number>();
    for (const patch of patches) {
      const title = normalizedTitle((patch as any)?.title);
      if (title) patchTitleCounts.set(title, (patchTitleCounts.get(title) ?? 0) + 1);
    }
    for (const patch of patches) {
      if (!patch || typeof patch !== 'object') continue;
      const id = String((patch as any).id ?? '').trim();
      const title = normalizedTitle((patch as any).title);
      const uniqueTitleIndex = title
        && patchTitleCounts.get(title) === 1
        && (titleIndexes.get(title)?.length ?? 0) === 1
        ? titleIndexes.get(title)?.[0]
        : undefined;
      const index = (id && idIndex.get(id) !== undefined) ? idIndex.get(id) : uniqueTitleIndex;
      if (index === undefined) {
        rows.push(patch as StateRow);
        if (id) idIndex.set(id, rows.length - 1);
        if (title) titleIndexes.set(title, [...(titleIndexes.get(title) ?? []), rows.length - 1]);
      } else {
        const existing = rows[index];
        const source = patch as Record<string, unknown>;
        rows[index] = {
          ...existing,
          ...source,
          // 标题唯一命中时必须继续沿用旧稳定 ID；模型补丁不能借机分裂同一对象。
          id: existing.id,
          fields: {
            ...(existing.fields ?? {}),
            ...(source.fields && typeof source.fields === 'object' ? source.fields as Record<string, unknown> : {}),
          },
        } as StateRow;
        idIndex.set(existing.id, index);
      }
    }
    merged[table.key] = rows;
  }
  return normalizeSnapshot(merged, previous, registry);
}

function identityToken(value: unknown): string {
  return String(value ?? '').normalize('NFKC').toLowerCase().replace(/[\s·•._—–\-|｜:：()（）【】\[\]]+/g, '');
}

function textList(value: unknown): string[] {
  return Array.isArray(value) ? value.map((item) => String(item ?? '').trim()).filter(Boolean) : [];
}

/**
 * facts 是事件线真相来源；行只输出内容补丁。这里在本地把同一轮多事件线重新挂回受影响对象，
 * 避免模型为每一行重复 factIds/eventIds/recall，降低输出体积并防止两条线互相覆盖。
 */
export function attachLocalFactMetadata(
  parsedSnapshot: Record<string, unknown>,
  rawFacts: unknown[],
  registry: ReturnType<typeof normalizeTableRegistry>,
): Record<string, unknown> {
  const facts = rawFacts.filter((item) => item && typeof item === 'object').map((item) => item as Record<string, unknown>);
  for (const table of enabledTables(registry)) {
    const patches = parsedSnapshot[table.key];
    if (!Array.isArray(patches)) continue;
    for (const rawPatch of patches) {
      if (!rawPatch || typeof rawPatch !== 'object') continue;
      const patch = rawPatch as Record<string, unknown>;
      const title = String(patch.title ?? '').trim();
      const id = String(patch.id ?? '').trim();
      const rowTokens = new Set([title, id].map(identityToken).filter(Boolean));
      let matched = facts.filter((fact) => {
        const related = textList(fact.related_entities ?? fact.relatedEntities).map(identityToken).filter(Boolean);
        if (related.some((token) => rowTokens.has(token))) return true;
        if (table.role === 'events' && identityToken(fact.title) === identityToken(title)) return true;
        return false;
      });
      // 单事件轮次允许安全回退；多事件轮次绝不凭模糊关键词把无关线挂到一起。
      if (!matched.length && facts.length === 1) matched = facts;
      const factIds = [...new Set([
        ...textList(patch.factIds ?? patch.fact_ids),
        ...matched.map((fact) => String(fact.fact_id ?? fact.factId ?? '').trim()).filter(Boolean),
      ])];
      const eventIds = [...new Set([
        ...textList(patch.eventIds ?? patch.event_ids),
        String(patch.eventId ?? patch.event_id ?? '').trim(),
        ...matched.map((fact) => String(fact.event_id ?? fact.eventId ?? '').trim()).filter(Boolean),
      ].filter(Boolean))];
      patch.factIds = factIds;
      patch.eventIds = eventIds;
      patch.eventId = eventIds[0] ?? '';
      if (!patch.recall || typeof patch.recall !== 'object') {
        const keywords = textList(patch.keywords);
        patch.recall = { any: [...new Set([title, ...keywords].filter(Boolean))], all: [], exclude: [] };
      }
      const hasRelatedEvents = table.fields.some((field) => field.key === 'relatedEvents');
      if (hasRelatedEvents && eventIds.length) {
        patch.relatedEvents = [...new Set([...textList(patch.relatedEvents), ...eventIds])];
      }
    }
  }
  return parsedSnapshot;
}

function assertRegistryCurrent(expectedFingerprint: string): void {
  const current = enabledTables(normalizeTableRegistry(getSettings().tableRegistry));
  if (registryFingerprint(current) !== expectedFingerprint) {
    throw new RegistryChangedError('表格定义已变化，旧状态结果不再提交');
  }
}


/** 状态任务一次产出内部事实变更和动态快照，成功后由主流水线提交核心结果。 */
export async function runStateExtraction(artifact: MessageArtifact, force = false): Promise<StateSnapshot> {
  const settings = getSettings();
  const registry = normalizeTableRegistry(settings.tableRegistry);
  const active = enabledTables(registry);
  const expectedRegistryFingerprint = registryFingerprint(active);
  const previous = dedupeStrongStateRows(previousSnapshot(artifact.messageIndex), registry);
  const chatState = await getChatState(artifact.chatKey);
  const activeFacts = (chatState.internalFacts ?? [])
    .filter((fact) => fact.active || fact.unresolvedItems.length > 0 || !fact.consumedBySmallSummaryId)
    .slice(-120);
  const request = {
    task: 'state' as const,
    systemPrompt: stateSystemPrompt(registry),
    prompt: stateUserPrompt(previous, artifact.playerText, artifact.assistantText, registry, activeFacts),
    maxTokens: 4096,
    requestPurpose: 'fixed-text' as const,
  };
  const inputFingerprint = hashText(JSON.stringify(request));
  assertRegistryCurrent(expectedRegistryFingerprint);
  if (!force && artifact.stages.state.status === 'success' && artifact.snapshot && artifact.stateInputFingerprint === inputFingerprint) {
    return normalizeSnapshot(artifact.snapshot, artifact.snapshot, registry);
  }
  markStage(artifact, 'state', 'running');
  await putArtifact(artifact);

  try {
    const raw = await generateTask(request);
    let parsed: Record<string, any>;
    try {
      parsed = parseStateTextOutput(raw, previous, registry, activeFacts);
    } catch (error) {
      const preview = safeText(raw, 1200).replace(/\s+/g, ' ').trim();
      throw new Error(`状态表固定文本无法解析：${toErrorMessage(error)}${preview ? `；返回片段：${preview}` : ''}`, { cause: error });
    }
    if (typeof parsed.turnSummary !== 'string') throw new Error('状态返回缺少 turnSummary 字符串');
    if (!Array.isArray(parsed.facts)) throw new Error('状态返回缺少 facts 数组');
    if (!parsed.snapshot || typeof parsed.snapshot !== 'object' || Array.isArray(parsed.snapshot)) throw new Error('状态返回缺少 snapshot 根对象');
    // 兼容旧模型返回 state/characters；只迁移到当前注册的角色视图，其他未注册键仍拒绝。
    const characterTable = active.find((table) => table.role === 'characters' || table.role === 'state');
    if (characterTable) {
      if (Array.isArray(parsed.snapshot.state) && !Array.isArray(parsed.snapshot[characterTable.key])) parsed.snapshot[characterTable.key] = parsed.snapshot.state;
      if (Array.isArray(parsed.snapshot.characters) && !Array.isArray(parsed.snapshot[characterTable.key])) parsed.snapshot[characterTable.key] = parsed.snapshot.characters;
      if (characterTable.key !== 'state') delete parsed.snapshot.state;
      if (characterTable.key !== 'characters') delete parsed.snapshot.characters;
    }
    const returnedKeys = Object.keys(parsed.snapshot);
    const activeKeys = new Set(active.map((table) => table.key));
    const legacyViewKeys = new Set(['focus', 'state', 'characters', 'skills', 'relationships']);
    for (const key of returnedKeys) if (!activeKeys.has(key) && !legacyViewKeys.has(key)) throw new Error(`模型返回未注册或已停用表格：${key}`);
    parsed.snapshot = attachLocalFactMetadata(migrateSnapshotTables(parsed.snapshot, registry), parsed.facts, registry);
    for (const [key, value] of Object.entries(parsed.snapshot)) {
      if (activeKeys.has(key) && !Array.isArray(value)) throw new Error(`状态表 ${key} 必须是数组`);
    }
    assertStateBusinessShape(parsed, active);

    assertArtifactCommitCurrent(artifact);
    assertRegistryCurrent(expectedRegistryFingerprint);
    const mergedViews = preserveStableObjectIds(previous, mergeStateRowPatches(previous, parsed.snapshot, registry), registry);
    const normalized = filterPassiveObservers(
      enforceObjectViewAllocation(
        removeFocusCharacterDuplicates(
          preserveObjectBaseLayers(
            previous,
            preservePersistentCharacters(previous, preserveProtectedRows(previous, mergedViews, registry), registry),
            registry,
          ),
          registry,
        ),
        registry,
      ),
      registry,
    );
    artifact.factPackage = normalizeFactPackage(parsed, artifact.messageKey);
    artifact.snapshot = normalized;
    artifact.stateInputFingerprint = inputFingerprint;
    markStage(artifact, 'state', 'success');
    await putArtifact(artifact);
    return normalized;
  } catch (error) {
    if (error instanceof RegistryChangedError) {
      markStage(artifact, 'state', 'idle');
      await putArtifact(artifact);
      throw error;
    }
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) {
      markStage(artifact, 'state', 'cancelled', toErrorMessage(error));
      await putArtifact(artifact);
      throw error;
    }
    markStage(artifact, 'state', 'failed', toErrorMessage(error));
    await putArtifact(artifact);
    throw error;
  }
}
