/**
 * 模块职责：兼容旧小总结沉降计划，并按动态表格角色应用代码保护。
 * 维护边界：内部事实消费不依赖可见表；手工/锁定行、当前相关主体和未结束事件不得自动删除。
 */
import type { TableDefinition, TableRole } from '../constants';
import type { ActivityState, SedimentationPlan, StateRow, StateSnapshot, SummaryArtifact } from '../types';
import { DEFAULT_TABLE_REGISTRY, normalizeTableRegistry, tableByRole } from './table-registry';
import { normalizeSnapshot } from './snapshot';

// 新记忆漏斗保留事件与区域对象，在同一条目内把细节从当前沉降到近期/历史；只有已离开的时空切片允许退出。
const REMOVABLE_ROLES = new Set<TableRole>(['spacetime']);
const SETTLED_STATUS = /(已结束|已完成|已关闭|已失效|已归档|已替代|resolved|closed|completed|expired|archived|superseded|historical)/i;
function registryOrDefault(registry?: TableDefinition[]): TableDefinition[] {
  return normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
}
function canRemoveRow(table: TableDefinition, row: StateRow, snapshot: StateSnapshot): boolean {
  if (!REMOVABLE_ROLES.has(table.role)) return false;
  if (row.source === 'manual' || row.locked || !SETTLED_STATUS.test(`${row.status} ${row.content}`)) return false;
  if (table.role === 'spacetime' && (snapshot[table.key]?.length ?? 0) <= 1) return false;
  return true;
}
function canAdvanceActivity(current: ActivityState | undefined, target: ActivityState, row: StateRow): boolean {
  if (row.source === 'manual' || row.locked || current === '当前在场' || current === '当前相关') return false;
  const sequence: ActivityState[] = ['离场但仍活跃', '休眠', '长期休眠', '已归档'];
  const from = sequence.indexOf(current ?? '未标注');
  const to = sequence.indexOf(target);
  if (to < 0) return false;
  if (current === '未标注') return target === '休眠';
  return from >= 0 && to === Math.min(from + 1, sequence.length - 1);
}

/**
 * 小总结只基于内部事实生成文本；可见表沉降由代码按 event_id / fact_id 推导，
 * 不接受模型任意指定行号。事件与区域作为独立信息点继续保留并写入近期/历史；只有已经结束的旧时空切片可成为退出候选。
 */
export function deriveEventSedimentationPlan(
  snapshot: StateSnapshot,
  eventId: string,
  factIds: string[],
  closed: boolean,
  registry?: TableDefinition[],
): SedimentationPlan {
  if (!closed) return { removeRowIds: [], characterActivityUpdates: [], notes: ['事件尚未结束，不执行可见视图退出。'] };
  const tables = registryOrDefault(registry);
  const factSet = new Set(factIds);
  const removeRowIds: string[] = [];
  for (const table of tables.filter((item) => REMOVABLE_ROLES.has(item.role))) {
    for (const row of snapshot[table.key] ?? []) {
      const linked = (row.eventIds ?? (row.eventId ? [row.eventId] : [])).includes(eventId) || (row.factIds ?? []).some((id) => factSet.has(id));
      if (linked && SETTLED_STATUS.test(`${row.status} ${row.content}`)) removeRowIds.push(row.id);
    }
  }
  return {
    removeRowIds: [...new Set(removeRowIds)],
    characterActivityUpdates: [],
    notes: ['由代码按 event_id / fact_id 生成旧时空退出候选；事件、区域和对象条目保留，在条目内部完成近期与历史沉降。'],
  };
}

export function applySedimentation(snapshot: StateSnapshot, summary: SummaryArtifact, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const plan = summary.sedimentation;
  if (!plan) return normalizeSnapshot(snapshot, snapshot, tables);
  const next = normalizeSnapshot(snapshot, snapshot, tables);
  const requested = new Set(plan.removeRowIds);
  const applied: string[] = [];
  const ignored: string[] = [];
  for (const table of tables.filter((item) => REMOVABLE_ROLES.has(item.role))) {
    next[table.key] = (next[table.key] ?? []).filter((row) => {
      if (!requested.has(row.id)) return true;
      if (canRemoveRow(table, row, next)) { applied.push(row.id); return false; }
      ignored.push(row.id); return true;
    });
  }
  const stateKey = tableByRole(tables, 'characters', false)?.key || tableByRole(tables, 'state', false)?.key;
  const stateRows = stateKey ? next[stateKey] ?? [] : [];
  for (const update of plan.characterActivityUpdates) {
    const row = stateRows.find((item) => item.id === update.rowId);
    if (!row || !canAdvanceActivity(row.lifecycle?.activity, update.activity, row)) { ignored.push(update.rowId); continue; }
    row.lifecycle ||= { existence: '未标注', activity: '未标注', memory: '未标注', evidenceLevel: '未知', evidence: '', returnConditions: [], returnBlockers: [] };
    row.lifecycle.activity = update.activity;
    row.status = update.activity;
    applied.push(update.rowId);
  }
  const normalizedPlan: SedimentationPlan = { ...plan, appliedRowIds: [...new Set(applied)], ignoredRowIds: [...new Set(ignored)] };
  summary.sedimentation = normalizedPlan;
  return next;
}
