/**
 * 模块职责：依据动态表格注册表构造内部事实与行级状态固定文本协议。
 * 维护边界：只提取已发生、已显影内容；未返回行由插件保留，禁止模型重写完整旧快照。
 */
import type { TableDefinition, TableFieldDefinition } from '../constants';
import type { InternalFact, StateRow, StateSnapshot } from '../types';
import { DEFAULT_TABLE_REGISTRY, enabledTables, normalizeTableRegistry } from '../domain/table-registry';

const COMMON_FIELD_KEYS = new Set([
  'id', 'title', 'content', 'keywords', 'status', 'baseContent', 'currentFacts', 'currentStates',
  'recentHistory', 'solidifiedHistory', 'relatedObjects', 'relatedEvents',
]);
const ACTIVE_STATUS_RE = /current|active|进行|当前|活跃|未决|持续|开放|受限|暂停/i;
const MAX_INDEX_ROWS = 120;
const MAX_FULL_ROWS = 16;
const MAX_FULL_ROWS_PER_TABLE = 6;
const MAX_FACTS = 18;

function tables(registry?: TableDefinition[]): TableDefinition[] {
  return enabledTables(normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]));
}

function extraFieldInstruction(field: TableFieldDefinition): string {
  return `${field.key}（${field.label}）：${field.description || '按字段名称填写'}${field.required ? '，必填' : ''}`;
}

function compactRegistryDescription(active: TableDefinition[]): string {
  return active.map((table, index) => {
    const defaultTable = DEFAULT_TABLE_REGISTRY.find((item) => item.key === table.key);
    const extras = table.fields
      .filter((field) => {
        if (!COMMON_FIELD_KEYS.has(field.key)) return true;
        const base = defaultTable?.fields.find((item) => item.key === field.key);
        return !base || base.label !== field.label || base.description !== field.description || base.required !== field.required;
      })
      .map(extraFieldInstruction)
      .join('；');
    return `${index + 1}. ${table.key}｜${table.name}｜用途：${table.purpose}${extras ? `｜扩展字段：${extras}` : ''}`;
  }).join('\n');
}

export function stateSystemPrompt(registry?: TableDefinition[]): string {
  const active = tables(registry);
  const keys = active.map((table) => `${table.key}（${table.name}）`).join('、');
  return `你是“镜渊”事实提取与状态维护器。你不续写故事，不推测未显影内容。

你必须返回固定文本协议，禁止返回 JSON、Markdown 表格、代码围栏、解释或思考标签。
允许的块只有 <MA_TURN>、<MA_FACT>、<MA_ROW>；每个字段独占一行，使用英文等号“=”连接。列表字段通过重复同名行表达，禁止自行发明字段。

【核心原则】
1. 模型不生成任何 id、fact_id、event_id，也不重写整张表。对象匹配、稳定 ID、同轮合并和去重全部由插件完成。
2. <MA_ROW> 只返回本轮新增或变化的对象。未返回条目由插件保留。
3. table 只能填写启用表格键或名称：${keys || '（无）'}。
4. object 填稳定对象名；正文出现的新称呼用 keyword 重复行补充。不要把同一对象拆成两个 <MA_ROW>。
5. field.<字段键或表头> 只填写本轮需要更新的字段。string[] 字段可重复多行；string 字段只写一行。
6. recentHistory 与 solidifiedHistory 只由总结维护，状态提取禁止写入。
7. 关系变化写入角色 relationshipStates；能力变化写入 abilityStates。不得单独创建关系表或技能表。
8. 不输出焦点条目。焦点只由玩家设置。

【事实边界】
- 一轮正文可推进多条事件线，分别输出多个 <MA_FACT>；event 填事件稳定名称，不填 ID。
- 只记录对后续仍有作用且来源明确的事实。同场、普通对话、表情、推测、围观和临时动作不得自动创建长期对象或关系。
- 他人陈述、传闻和推测使用 reported 或 uncertain，不得升级为 confirmed。
- 当前地点只写时空；区域只记录离开后仍成立的定义、现行事实或持续变化。
- 场景切换后，已离开的旧场景不得继续标为当前。
- 过程压缩为当前结果，未决事项不得强行闭合。

【固定文本格式】
<MA_TURN>
summary=本轮变化概括
</MA_TURN>

<MA_FACT>
event=事件稳定名称
title=本条事实名称
type=event
status=active
operation=update
confidence=confirmed
occurred=已发生结果
unresolved=尚未解决事项
time_start=当前
time_end=
time_label=
related=直接受影响对象
keyword=事实关键词
</MA_FACT>

<MA_ROW>
table=characters
object=对象稳定名称
summary=当前有效摘要
status=active
keyword=对象别名
field.currentFacts=当前客观事实
field.currentStates=当前阶段状态
field.relatedObjects=直接关联对象
field.relatedEvents=直接关联事件名称
lifecycle.existence=存活
lifecycle.activity=当前相关
lifecycle.memory=未标注
lifecycle.evidenceLevel=已确认
lifecycle.evidence=正文明确内容
lifecycle.returnConditions=
lifecycle.returnBlockers=
</MA_ROW>

没有事实或条目变化时可省略对应块，但至少输出一个 <MA_TURN>。不要输出空占位 <MA_FACT>/<MA_ROW>。

【启用表格与字段】
${compactRegistryDescription(active) || '当前没有启用表格；不要输出 <MA_ROW>。'}`;
}
function normalizeSearchText(value: unknown): string {
  return String(value ?? '').normalize('NFKC').toLowerCase().replace(/[\s\p{P}\p{S}]+/gu, '');
}

function stringList(value: unknown): string[] {
  return Array.isArray(value) ? value.map((item) => String(item ?? '').trim()).filter(Boolean) : [];
}

function boundedList(value: unknown, count: number, chars: number): string[] {
  return stringList(value).slice(-count).map((item) => item.slice(0, chars));
}

function modelRow(row: StateRow): Record<string, unknown> {
  const output: Record<string, unknown> = {
    title: row.title,
    content: String(row.content || '').slice(0, 800),
    keywords: (row.keywords ?? []).slice(0, 16),
    status: row.status,
  };
  if (row.lifecycle) output.lifecycle = row.lifecycle;
  const fields = row.fields && typeof row.fields === 'object' ? row.fields : {};
  for (const [key, value] of Object.entries(fields)) {
    if (key === 'baseContent') output[key] = String(value ?? '').slice(0, 700);
    else if (key === 'currentFacts' || key === 'currentStates') output[key] = boundedList(value, 10, 260);
    else if (key === 'recentHistory') output[key] = boundedList(value, 4, 320);
    else if (key === 'solidifiedHistory') output[key] = boundedList(value, 2, 260);
    else if (Array.isArray(value)) output[key] = boundedList(value, 10, 220);
    else output[key] = String(value ?? '').slice(0, 600);
  }
  return output;
}
function rowIndex(row: StateRow): Record<string, unknown> {
  return {
    title: row.title,
    status: row.status,
    keywords: row.keywords,
  };
}

function rowTerms(row: StateRow): string[] {
  return [row.id, row.title, ...(row.keywords ?? [])]
    .map(normalizeSearchText)
    .filter((term) => term.length >= 2);
}

function rowMatches(row: StateRow, source: string): boolean {
  return rowTerms(row).some((term) => source.includes(term));
}

function relatedTokens(row: StateRow): string[] {
  const fields = row.fields && typeof row.fields === 'object' ? row.fields : {};
  return [
    ...stringList((fields as any).relatedObjects),
    ...stringList((fields as any).relatedEvents),
  ].map(normalizeSearchText).filter(Boolean);
}

function compactSnapshotContext(previous: StateSnapshot, active: TableDefinition[], sourceText: string): {
  index: Record<string, unknown[]>;
  relevant: Record<string, unknown[]>;
} {
  const source = normalizeSearchText(sourceText);
  const all: Array<{ table: TableDefinition; row: StateRow; direct: boolean; active: boolean; order: number }> = [];
  let order = 0;
  for (const table of active) {
    for (const row of previous[table.key] ?? []) {
      const direct = rowMatches(row, source);
      const activeRow = table.role === 'spacetime' || table.role === 'events' && ACTIVE_STATUS_RE.test(row.status) || ACTIVE_STATUS_RE.test(row.status);
      all.push({ table, row, direct, active: activeRow, order: order += 1 });
    }
  }

  const seedTokens = new Set<string>();
  for (const item of all) {
    if (!item.direct && !item.active) continue;
    for (const term of rowTerms(item.row)) seedTokens.add(term);
  }
  const related = (item: typeof all[number]) => relatedTokens(item.row).some((term) => seedTokens.has(term));
  const priority = (item: typeof all[number]) => item.direct ? 4 : item.table.role === 'spacetime' ? 3 : related(item) ? 2 : item.active ? 1 : 0;
  const sorted = [...all].sort((a, b) => priority(b) - priority(a) || String(b.row.updatedAt || '').localeCompare(String(a.row.updatedAt || '')) || a.order - b.order);

  const index: Record<string, unknown[]> = {};
  for (const item of sorted.slice(0, MAX_INDEX_ROWS)) {
    (index[item.table.key] ||= []).push(rowIndex(item.row));
  }

  const relevant: Record<string, unknown[]> = {};
  let total = 0;
  const perTable = new Map<string, number>();
  for (const item of sorted) {
    if (priority(item) <= 0 && (previous[item.table.key]?.length ?? 0) > 8) continue;
    if (total >= MAX_FULL_ROWS) break;
    const count = perTable.get(item.table.key) ?? 0;
    if (count >= MAX_FULL_ROWS_PER_TABLE) continue;
    (relevant[item.table.key] ||= []).push(modelRow(item.row));
    perTable.set(item.table.key, count + 1);
    total += 1;
  }
  return { index, relevant };
}

function factMatches(fact: InternalFact, source: string): boolean {
  const terms = [fact.factId, fact.eventId, fact.title, ...fact.keywords, ...fact.relatedEntities]
    .map(normalizeSearchText)
    .filter((term) => term.length >= 2);
  return terms.some((term) => source.includes(term));
}

function activeFactPayload(facts: InternalFact[], sourceText: string): Record<string, unknown>[] {
  const source = normalizeSearchText(sourceText);
  const selected = facts.length <= MAX_FACTS
    ? facts
    : facts.filter((fact) => factMatches(fact, source) || fact.unresolvedItems.length > 0 || fact.active).slice(-MAX_FACTS);
  const fallback = selected.length ? selected : facts.slice(-12);
  return fallback.map((fact) => ({
    occurred: fact.occurredFacts,
    unresolved: fact.unresolvedItems,
    status: fact.status,
    time_range: fact.timeRange,
    related_entities: fact.relatedEntities,
    title: fact.title,
    type: fact.type,
    keywords: fact.keywords,
    confidence: fact.confidence,
    active: fact.active,
  }));
}

function contextValue(value: unknown): string {
  return String(value ?? '')
    .replace(/<\/?MA_[A-Z_]+>/gi, (tag) => tag.replace(/</g, '＜').replace(/>/g, '＞'))
    .replace(/\r\n?/g, '\n')
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean)
    .join(' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pushContextField(lines: string[], key: string, value: unknown): void {
  if (Array.isArray(value)) {
    for (const item of value) pushContextField(lines, key, item);
    return;
  }
  if (value && typeof value === 'object') {
    for (const [nestedKey, nestedValue] of Object.entries(value as Record<string, unknown>)) {
      pushContextField(lines, `${key}.${nestedKey}`, nestedValue);
    }
    return;
  }
  const text = contextValue(value);
  if (text) lines.push(`${key}=${text}`);
}

function contextFactBlocks(payload: Record<string, unknown>[]): string {
  if (!payload.length) return '（无）';
  return payload.map((fact) => {
    const lines = ['<MA_CONTEXT_FACT>'];
    pushContextField(lines, 'title', fact.title);
    pushContextField(lines, 'type', fact.type);
    pushContextField(lines, 'status', fact.status);
    pushContextField(lines, 'confidence', fact.confidence);
    pushContextField(lines, 'active', fact.active);
    const time = fact.time_range && typeof fact.time_range === 'object'
      ? fact.time_range as Record<string, unknown>
      : {};
    pushContextField(lines, 'time_start', time.start);
    pushContextField(lines, 'time_end', time.end);
    pushContextField(lines, 'time_label', time.label);
    pushContextField(lines, 'occurred', fact.occurred);
    pushContextField(lines, 'unresolved', fact.unresolved);
    pushContextField(lines, 'related', fact.related_entities);
    pushContextField(lines, 'keyword', fact.keywords);
    lines.push('</MA_CONTEXT_FACT>');
    return lines.join('\n');
  }).join('\n');
}

function contextIndexBlocks(index: Record<string, unknown[]>): string {
  const blocks: string[] = [];
  for (const [table, rows] of Object.entries(index)) {
    for (const source of rows) {
      const row = source && typeof source === 'object' ? source as Record<string, unknown> : {};
      const lines = ['<MA_CONTEXT_INDEX>'];
      pushContextField(lines, 'table', table);
      pushContextField(lines, 'object', row.title);
      pushContextField(lines, 'status', row.status);
      pushContextField(lines, 'keyword', row.keywords);
      lines.push('</MA_CONTEXT_INDEX>');
      blocks.push(lines.join('\n'));
    }
  }
  return blocks.join('\n') || '（无）';
}

function contextRowBlocks(relevant: Record<string, unknown[]>): string {
  const blocks: string[] = [];
  for (const [table, rows] of Object.entries(relevant)) {
    for (const source of rows) {
      const row = source && typeof source === 'object' ? source as Record<string, unknown> : {};
      const lines = ['<MA_CONTEXT_ROW>'];
      pushContextField(lines, 'table', table);
      pushContextField(lines, 'object', row.title);
      pushContextField(lines, 'summary', row.content);
      pushContextField(lines, 'status', row.status);
      pushContextField(lines, 'keyword', row.keywords);
      if (row.lifecycle && typeof row.lifecycle === 'object') {
        for (const [key, value] of Object.entries(row.lifecycle as Record<string, unknown>)) {
          pushContextField(lines, `lifecycle.${key}`, value);
        }
      }
      for (const [key, value] of Object.entries(row)) {
        if (['title', 'content', 'status', 'keywords', 'lifecycle'].includes(key)) continue;
        pushContextField(lines, `field.${key}`, value);
      }
      lines.push('</MA_CONTEXT_ROW>');
      blocks.push(lines.join('\n'));
    }
  }
  return blocks.join('\n') || '（无）';
}

export function stateUserPrompt(
  previous: StateSnapshot,
  playerText: string,
  assistantText: string,
  registry?: TableDefinition[],
  internalFacts: InternalFact[] = [],
  repair = false,
): string {
  const active = tables(registry);
  const sourceText = `${playerText}\n${assistantText}`;
  const context = compactSnapshotContext(previous, active, sourceText);
  return `【相关内部事实：仅用于判断事件延续，不要照抄为新事实】\n${contextFactBlocks(activeFactPayload(internalFacts, sourceText))}

【旧视图索引：只用于识别已有对象】\n${contextIndexBlocks(context.index)}

【与本轮相关的旧行全文：只用于判断更新内容】\n${contextRowBlocks(context.relevant)}

【玩家本轮输入】\n${playerText || '（空）'}

【角色本轮正文】\n${assistantText}

只返回固定文本协议。只写本轮事实变化和最小条目补丁；未返回条目由插件保留。不要返回 JSON，不要输出 id/fact_id/event_id，不要复制无变化旧行。${repair ? '\n上一次固定文本格式不完整；这次严格使用 <MA_TURN>/<MA_FACT>/<MA_ROW>。' : ''}`;
}

export function stateTextProtocolDescription(registry?: TableDefinition[]): string {
  const active = tables(registry);
  return `固定文本块：<MA_TURN>、<MA_FACT>、<MA_ROW>。启用表格：${active.map((table) => `${table.key}(${table.name})`).join('、')}。模型不返回任何稳定 ID；插件按 table + object + keyword 匹配旧条目并本地生成新 ID。`;
}

