/**
 * 模块职责：把承载当前、近期与历史层的对象/事件表格条目转换为 constant / trigger / vector 三种世界书文档。
 * 维护边界：不使用数值权重决定记忆进入上下文；不同信息点可共享 fact_id/event_id，去重只按条目身份与完全相同内容，再按总容量裁剪。
 */
import type { TableDefinition, TableRole } from '../constants';
import type { CharacterLifecycle, InternalFact, RecallConditions, StateSnapshot, StateRow, SummaryArtifact } from '../types';
import { customizedFieldLabel, DEFAULT_TABLE_REGISTRY, enabledTables, normalizeTableRegistry, tableByRole } from './table-registry';
import { enforceObjectViewAllocation, filterPassiveObservers, normalizeSnapshot } from './snapshot';
import { dedupeStrongStateRows } from './state-text';
import { safeText } from '../core/utils';
import { canonicalObjectTitle } from './object-identity';
import { isPurePassiveObserverText } from './observer';

export type LorebookRecallMode = 'constant' | 'trigger' | 'vector';
export interface LorebookDocument {
  key: string;
  logicalKey?: string;
  comment: string;
  content: string;
  keywords: string[];
  constant: boolean;
  vectorized: boolean;
  /** 只用于 SillyTavern 世界书编辑器显示顺序，不能参与内容取舍。 */
  order: number;
  updatedAt: string;
  kind: string;
  recallMode: LorebookRecallMode;
  trigger: RecallConditions;
  vector: { similarityThreshold: number; maxResults: number };
  factIds: string[];
  eventIds: string[];
}
export interface LorebookPublishOptions {
  layout: 'semantic' | 'detailed';
  vectorize: boolean;
  latestContinuityConstant: boolean;
  registry?: TableDefinition[];
  internalFacts?: InternalFact[];
  similarityThreshold?: number;
  maxVectorResults?: number;
  totalCapacity?: number;
  focusObjectId?: string;
}

function registry(options?: LorebookPublishOptions): TableDefinition[] {
  return normalizeTableRegistry(options?.registry?.length ? options.registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
}
function uniq(values: string[], limit = 40): string[] {
  return [...new Set(values.map((item) => String(item || '').trim()).filter(Boolean))].slice(0, limit);
}
function lifecycleLines(lifecycle?: CharacterLifecycle): string[] {
  if (!lifecycle) return [];
  const lines = [`存在状态：${lifecycle.existence}`, `活跃状态：${lifecycle.activity}`, `记忆状态：${lifecycle.memory}`, `证据等级：${lifecycle.evidenceLevel}`];
  if (lifecycle.evidence) lines.push(`判断依据：${lifecycle.evidence}`);
  if (lifecycle.returnConditions.length) lines.push(`可能回流条件：${lifecycle.returnConditions.join('；')}`);
  if (lifecycle.returnBlockers.length) lines.push(`阻止回流条件：${lifecycle.returnBlockers.join('；')}`);
  return lines;
}
function rowContent(table: TableDefinition, row: StateRow): string {
  const titleLabel = customizedFieldLabel(table, 'title', '');
  const statusLabel = customizedFieldLabel(table, 'status', '当前状态');
  const contentLabel = customizedFieldLabel(table, 'content', '当前记录');
  const keywordsLabel = customizedFieldLabel(table, 'keywords', '触发词');
  const heading = titleLabel
    ? `[${table.name}｜${titleLabel}：${row.title}]`
    : `[${table.name}：${row.title}]`;
  const lines = [heading, ...lifecycleLines(row.lifecycle)];
  if (row.status) lines.push(`${statusLabel}：${row.status}`);
  if (row.content) lines.push(`${contentLabel}：${row.content}`);
  for (const field of table.fields) {
    if (!row.fields || !(field.key in row.fields)) continue;
    const value = row.fields[field.key];
    if (Array.isArray(value) && value.length) lines.push(`${field.label}：${value.join('、')}`);
    else if (String(value ?? '').trim()) lines.push(`${field.label}：${String(value)}`);
  }
  if (row.keywords.length) lines.push(`${keywordsLabel}：${row.keywords.join('、')}`);
  if (row.factIds?.length) lines.push(`事实ID：${row.factIds.join('、')}`);
  const eventIds = row.eventIds ?? (row.eventId ? [row.eventId] : []);
  if (eventIds.length) lines.push(`事件ID：${eventIds.join('、')}`);
  if (row.locked || row.lockMode === 'all') lines.push('维护权限：玩家完全锁定；基础与状态均不得自动修改。');
  else if (row.source === 'manual' || row.lockMode === 'base') lines.push('维护权限：玩家基础保护；基础内容不得自动改写，当前状态可依据明确事实更新。');
  return lines.join('\n');
}
function rowSearchText(row: StateRow): string { return `${row.title} ${row.content} ${row.status} ${row.keywords.join(' ')}`; }
function isAudienceRow(row: StateRow): boolean {
  if (row.source === 'manual' || row.locked) return false;
  return isPurePassiveObserverText(rowSearchText(row));
}
function normalizedName(value: string): string { return canonicalObjectTitle(value); }
function aliases(title: string): string[] {
  const raw = String(title || '').trim();
  return uniq([normalizedName(raw), ...raw.split(/[｜|:：—–-]/).map(normalizedName)], 12);
}

/**
 * 活跃视图和世界书共同过滤纯旁观者，人工/锁定行不自动删除。
 * 发布前过滤只依据对象事实和保护规则；焦点不得改变对象是否参与发布，唯一效果在 recallModeFor。
 */
export function filterSnapshotForLorebook(snapshot: StateSnapshot, customRegistry?: TableDefinition[]): StateSnapshot {
  const tables = normalizeTableRegistry(customRegistry?.length ? customRegistry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
  // 世界书是长期记忆的最终出口。即使旧快照来自早期版本，也必须在发布前再做一次
  // 名称唯一归并，不能把状态层遗留的同一对象切面继续扩散成多个世界书条目。
  const normalized = normalizeSnapshot(snapshot, snapshot, tables);
  const deduped = dedupeStrongStateRows(normalized, tables);
  const next = filterPassiveObservers(enforceObjectViewAllocation(deduped, tables), tables);
  const stateKey = tableByRole(tables, 'characters', false)?.key || tableByRole(tables, 'state', false)?.key;
  const eventKey = tableByRole(tables, 'events', false)?.key;
  const relationKey = tableByRole(tables, 'relationships', false)?.key;
  if (!stateKey) return next;
  const relevanceRows = [eventKey, relationKey].filter(Boolean).flatMap((key) => next[key as string] ?? []);
  const relevance = normalizedName(relevanceRows.map(rowSearchText).join(' '));
  next[stateKey] = (next[stateKey] ?? []).filter((row) => {
    if (row.source === 'manual' || row.locked) return true;
    if (isAudienceRow(row)) return false;
    const named = aliases(row.title).some((name) => name && relevance.includes(name));
    const direct = /(核心参与|直接相关|交战|对战|行动者|目标|当事人)/i.test(rowSearchText(row));
    return named || direct || !relevance;
  });
  const retainedNames = new Set(next[stateKey].flatMap((row) => aliases(row.title)));
  for (const table of enabledTables(tables)) {
    if (['focus', 'spacetime', 'characters', 'state', 'events', 'globalChanges', 'foundations'].includes(table.role)) continue;
    next[table.key] = (next[table.key] ?? []).filter((row) => {
      if (table.role === 'custom' && safeText(row.fields?.migrationStatus, 80).trim() === '已归并') return false;
      if (row.source === 'manual' || row.locked) return true;
      if (isAudienceRow(row)) return false;
      const text = normalizedName(rowSearchText(row));
      return !retainedNames.size || [...retainedNames].some((name) => text.includes(name)) || table.role === 'regions';
    });
  }
  return next;
}

function defaultTrigger(row: StateRow): RecallConditions {
  const recall = row.recall ?? { any: [], all: [], exclude: [] };
  const any = uniq([...(recall.any ?? []), row.title, ...row.keywords], 32);
  return { any, all: uniq(recall.all ?? [], 20), exclude: uniq(recall.exclude ?? [], 20) };
}
function isEssentialState(row: StateRow): boolean {
  return /(不可缺失|昏迷|重伤|濒死|死亡|失踪|被拘禁|封印|当前在场|当前相关|核心参与)/i.test(rowSearchText(row));
}
function isHistoricalSpacetime(row: StateRow): boolean {
  return /(已离开|离开场景|历史场景|过去场景|非当前|已结束|已关闭|已归档|inactive|closed|ended|archived)/i.test(rowSearchText(row));
}
function currentSpacetimeRowId(rows: StateRow[]): string | undefined {
  const active = rows.filter((row) => !isHistoricalSpacetime(row));
  if (!active.length) return undefined;
  const explicit = active.filter((row) => /(当前场景|当前位置|当前地点|当前时空|正在此处|当前所在|current|active)/i.test(rowSearchText(row)));
  return (explicit.at(-1) ?? active.at(-1))?.id;
}
function recallModeFor(role: TableRole, row: StateRow, options: LorebookPublishOptions, currentSpacetimeId?: string): LorebookRecallMode {
  // 玩家手动焦点只授予该对象 constant；不依赖连续性常驻开关，也不改变其他召回规则。
  if ((role === 'characters' || role === 'state') && row.id === options.focusObjectId) return 'constant';
  // 总结已沉降回独立事件条目；启用语义召回时，由事件条目承接整条事件线的当前、近期与历史语义。
  // 人物、地区、物品等对象仍使用名称/别名触发，保证每个世界书条目只有一种召回方式。
  if (role === 'events' && options.vectorize) return 'vector';
  if (!options.latestContinuityConstant) return 'trigger';
  if (role === 'globalChanges') return 'constant';
  if (role === 'spacetime') return row.id === currentSpacetimeId ? 'constant' : 'trigger';
  // 角色是否常驻只由玩家设置的唯一焦点决定；伤势等状态仍由 SillyTavern 触发机制召回。
  if (role === 'characters' || role === 'state') return 'trigger';
  if (role === 'foundations' && /(必要|规则|制度|禁止|必须|不可)/i.test(rowSearchText(row))) return 'constant';
  return 'trigger';
}
function makeDocument(
  key: string, logicalKey: string, comment: string, content: string, kind: string, mode: LorebookRecallMode,
  trigger: RecallConditions, factIds: string[], eventIds: string[], updatedAt: string, options: LorebookPublishOptions,
): LorebookDocument {
  // 单条目只采用一种召回方式：constant、关键词 trigger 或事件线 vector。
  const actualMode: LorebookRecallMode = mode;
  return {
    key,
    logicalKey,
    comment: `[MA11] ${comment}`,
    content,
    keywords: actualMode === 'trigger' ? trigger.any : [],
    constant: actualMode === 'constant',
    vectorized: actualMode === 'vector',
    order: 0,
    updatedAt,
    kind,
    recallMode: actualMode,
    trigger,
    // SillyTavern 的相似度门槛和 Max Entries 是 Vector Storage 全局设置；这里只保存镜渊托管元数据。
    vector: { similarityThreshold: Math.min(0.99, Math.max(0, Number(options.similarityThreshold) || 0.72)), maxResults: Math.max(1, Math.round(Number(options.maxVectorResults) || 8)) },
    factIds: uniq(factIds, 100),
    eventIds: uniq(eventIds, 60),
  };
}

export function unconsumedSmallSummaries(small: SummaryArtifact[], large: SummaryArtifact[]): SummaryArtifact[] {
  const legacy = new Set(large.flatMap((item) => item.sourceSummaryIds ?? item.sourceKeys));
  return small.filter((item) => !item.solidifiedByLargeSummaryId && !item.supersededBySmallSummaryId && !legacy.has(item.id));
}

function tableDocuments(snapshot: StateSnapshot | undefined, options: LorebookPublishOptions): LorebookDocument[] {
  if (!snapshot) return [];
  const tables = registry(options);
  const filtered = filterSnapshotForLorebook(snapshot, tables);
  const docs: LorebookDocument[] = [];
  for (const table of enabledTables(tables)) {
    const rows = filtered[table.key] ?? [];
    const currentSpacetimeId = table.role === 'spacetime' ? currentSpacetimeRowId(rows) : undefined;
    for (const row of rows) {
      const mode = recallModeFor(table.role, row, options, currentSpacetimeId);
      const trigger = defaultTrigger(row);
      const titleToken = normalizedName(row.title) || row.id;
      docs.push(makeDocument(
        `view:${table.key}:${row.id}`,
        `view:${table.key}:${titleToken}`,
        `MA｜${table.name}｜${row.title}`,
        rowContent(table, row),
        `view:${table.role}`,
        mode,
        trigger,
        row.factIds ?? [],
        row.eventIds ?? (row.eventId ? [row.eventId] : []),
        row.updatedAt,
        options,
      ));
    }
  }
  return docs;
}

/** 常驻→明确触发→向量；不同信息点即使共享 fact_id/event_id 也必须保留，仅按条目身份与完全相同内容去重后按总容量裁剪。 */
export function selectLorebookDocuments(documents: LorebookDocument[], options: LorebookPublishOptions): LorebookDocument[] {
  const modeRank: Record<LorebookRecallMode, number> = { constant: 0, trigger: 1, vector: 2 };
  const selectionMode = (document: LorebookDocument): LorebookRecallMode => {
    const focusedCharacter = Boolean(
      options.focusObjectId
      && ['view:characters', 'view:state'].includes(document.kind)
      && document.key.endsWith(`:${options.focusObjectId}`),
    );
    // 焦点只改变入选角色的召回模式；选择、排序与容量裁剪仍按普通角色处理。
    return focusedCharacter ? 'trigger' : document.recallMode;
  };
  // 模式顺序来自产品召回流程；同一模式按事实更新时间和稳定键排序，绝不使用 UI order、importance 或权重裁剪记忆。
  const ordered = [...documents].sort((a, b) => {
    const modeDifference = modeRank[selectionMode(a)] - modeRank[selectionMode(b)];
    if (modeDifference) return modeDifference;
    const timeDifference = String(b.updatedAt || '').localeCompare(String(a.updatedAt || ''));
    return timeDifference || a.key.localeCompare(b.key);
  });
  const seenKeys = new Set<string>();
  const seenContents = new Set<string>();
  const output: LorebookDocument[] = [];
  let used = 0;
  let vectorCount = 0;
  const capacity = Math.max(2000, Math.round(Number(options.totalCapacity) || 24000));
  const maxVector = Math.max(1, Math.round(Number(options.maxVectorResults) || 8));
  for (const doc of ordered) {
    if (doc.recallMode === 'vector' && vectorCount >= maxVector) continue;
    if (seenKeys.has(doc.key)) continue;
    const contentIdentity = doc.content.replace(/\s+/g, ' ').trim();
    if (contentIdentity && seenContents.has(contentIdentity)) continue;
    const size = doc.content.length;
    if (used + size > capacity && output.length) continue;
    output.push({ ...doc, order: output.length + 100 });
    used += size;
    if (doc.recallMode === 'vector') vectorCount += 1;
    seenKeys.add(doc.key);
    if (contentIdentity) seenContents.add(contentIdentity);
  }
  return output;
}

export function buildSemanticLorebookDocuments(snapshot: StateSnapshot | undefined, _small: SummaryArtifact[], _large: SummaryArtifact[], options: LorebookPublishOptions): LorebookDocument[] {
  // 小总结/大总结是内部处理凭证，正文已经沉降进对象和事件条目的 recentHistory / solidifiedHistory。
  return selectLorebookDocuments(tableDocuments(snapshot, options), options);
}
export function buildDetailedLorebookDocuments(snapshot: StateSnapshot | undefined, _small: SummaryArtifact[], _large: SummaryArtifact[], options: LorebookPublishOptions): LorebookDocument[] {
  return selectLorebookDocuments(tableDocuments(snapshot, options), options);
}
export function buildLorebookDocuments(snapshot: StateSnapshot | undefined, small: SummaryArtifact[], large: SummaryArtifact[], options: LorebookPublishOptions): LorebookDocument[] {
  return options.layout === 'detailed' ? buildDetailedLorebookDocuments(snapshot, small, large, options) : buildSemanticLorebookDocuments(snapshot, small, large, options);
}
